export type CuratedTwinStyle = 'warm' | 'direct' | 'humorous' | 'wise' | 'neutral';

export interface CuratedPublicTwinSpec {
  name: string;
  slug: string;
  imageFile: string;
  contentType: string;
  size?: number;
  generatedPortrait?: boolean;
  categories: string[];
  style: CuratedTwinStyle;
  answerStyle: string;
  mainCategory: string;
  birthDate?: string;
  deathDate?: string;
  birthYear?: number;
  deathYear?: number;
  birthLabel?: string;
  deathLabel?: string;
  description: string;
  knowledge: string;
  rightsPosture: string;
  exampleQuestions: string[];
  searchIndex: string;
  sources: Array<{ title: string; publisher: string; url: string }>;
}

type Life =
  | { birthDate: string; deathDate: string }
  | { birthYear: number; deathYear: number; birthLabel: string; deathLabel: string };

type ProfileInput = {
  name: string;
  slug: string;
  mainCategory: string;
  categories: string[];
  style: CuratedTwinStyle;
  answerStyle: string;
  life: Life;
  description: string;
  lens: string;
  imageFile?: string;
  contentType?: string;
  size?: number;
  rightsPosture?: string;
  sources?: Array<{ title: string; publisher: string; url: string }>;
};

